import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Check if input length is within the buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            return;
        }

        byte[] buffer = new byte[10];
        byte[] nameBytes = name.getBytes();

        // Copy input bytes to buffer
        System.arraycopy(nameBytes, 0, buffer, 0, nameBytes.length);

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
